import React, { useState, useEffect } from "react";
import { Card, CardBody, Container, Row, Col, InputGroup, Input, Button, Table } from "reactstrap";
import { useNavigate } from "react-router-dom";
import Header from "components/Headers/Header.js";

const HealthInsuranceList = () => {
    const navigate = useNavigate();
    const [searchTerm, setSearchTerm] = useState("");
    const [healthInsurances, setHealthInsurances] = useState([]);

    useEffect(() => {
        fetch("http://localhost:5000/api/health-insurance")
            .then((res) => res.json())
            .then((data) => setHealthInsurances(data))
            .catch((error) => console.error("Lỗi tải danh sách BHYT:", error));
    }, []);

    const handleDelete = async (id) => {
        try {
            await fetch(`http://localhost:5000/api/health-insurance/${id}`, { method: "DELETE" });
            setHealthInsurances(healthInsurances.filter(item => item.id !== id));
        } catch (error) {
            console.error("Lỗi khi xóa BHYT:", error);
        }
    };

    const filteredHealthInsurances = healthInsurances.filter(item =>
        item.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        item.code.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <>
            <Header />
            <Container fluid className="mt-4">
                <Row className="mb-4">
                    <Col md="6">
                        <h3>Danh Sách Thẻ BHYT</h3>
                    </Col>
                    <Col md="3">
                        <InputGroup>
                            <Input
                                type="text"
                                placeholder="Tìm kiếm thẻ BHYT"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </InputGroup>
                    </Col>
                    <Col md="3" className="text-right">
                        <Button color="success" onClick={() => navigate("/admin/bhyt/add")}>+ Thêm BHYT</Button>
                    </Col>
                </Row>
                <Card>
                    <CardBody>
                        <Table bordered hover responsive>
                            <thead>
                                <tr>
                                    <th>STT</th>
                                    <th>Mã</th>
                                    <th>Họ và tên</th>
                                    <th>Nơi đăng kí khám</th>
                                    <th>Giá trị sử dụng</th>
                                    <th>Mã số</th>
                                    <th>Ngày cấp</th>
                                    <th>Nơi cấp</th>
                                    <th>Hành động</th>
                                </tr>
                            </thead>
                            <tbody>
                                {filteredHealthInsurances.map((item, index) => (
                                    <tr key={item.id}>
                                        <td>{index + 1}</td>
                                        <td>{item.code}</td>
                                        <td>{item.fullName}</td>
                                        <td>{item.placeOfRegistration}</td>
                                        <td>{item.validity}</td>
                                        <td>{item.serialNumber}</td>
                                        <td>{item.issueDate}</td>
                                        <td>{item.placeOfIssue}</td>
                                        <td>
                                            <Button color="danger" size="sm" onClick={() => handleDelete(item.id)}>Xóa</Button>
                                            <Button color="primary" size="sm" onClick={() => navigate(`/admin/bhyt/edit/${item.id}`)}>Sửa</Button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </Table>
                    </CardBody>
                </Card>
            </Container>
        </>
    );
};

export default HealthInsuranceList;
